import React, { useState } from "react";
import styles from "./Register.module.css";

interface RegisterProps {
  onSwitchToLogin: () => void;
  onClose: () => void;
  onRegister: (email: string, password: string, name: string) => void;
}

const Register: React.FC<RegisterProps> = ({
  onSwitchToLogin,
  onClose,
  onRegister,
}) => {
  const [email, setEmail] = useState("");
  const [password, setPassword] = useState("");
  const [confirmPassword, setConfirmPassword] = useState("");
  const [name, setName] = useState("");
  const [passwordError, setPasswordError] = useState<string | null>(null);

  const validatePassword = (pass: string): string | null => {
    if (pass.length < 6) {
      return "Пароль должен содержать не менее 6 символов";
    }
    const specialChars = (pass.match(/[!@#$%^&*]/g) || []).length;
    if (specialChars < 2) {
      return "Пароль должен содержать не менее 2 спецсимволов (!@#$%^&*)";
    }
    if (!/[A-Z]/.test(pass)) {
      return "Пароль должен содержать как минимум одну заглавную букву";
    }
    return null;
  };

  const handlePasswordChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    const newPassword = e.target.value;
    setPassword(newPassword);
    setPasswordError(validatePassword(newPassword));
  };

  const handleRegister = () => {
    if (!email || !name) {
      return;
    }
    if (password !== confirmPassword) {
      setPasswordError("Пароли не совпадают");
      return;
    }
    if (passwordError) {
      return;
    }
    onRegister(email, password, name);
  };

  return (
    <div className={styles.registerContainer}>
      <img
        src={`${process.env.PUBLIC_URL}/images/logo.svg`}
        alt="SkyFitnessPro"
        className={styles.logo}
      />

      <div className={styles.formContainer}>
        <input
          type="text"
          placeholder="Имя"
          className={styles.inputField}
          value={name}
          onChange={(e) => setName(e.target.value)}
        />

        <input
          type="email"
          placeholder="Эл.почта"
          className={styles.inputField}
          value={email}
          onChange={(e) => setEmail(e.target.value)}
        />

        <input
          type="password"
          placeholder="Пароль"
          className={styles.inputField}
          value={password}
          onChange={handlePasswordChange}
        />

        <input
          type="password"
          placeholder="Повторить пароль"
          className={styles.inputField}
          value={confirmPassword}
          onChange={(e) => setConfirmPassword(e.target.value)}
        />

        {passwordError && (
          <div className={styles.errorMessage}>{passwordError}</div>
        )}

        <button
          className={styles.registerButton}
          onClick={handleRegister}
          disabled={!!passwordError || !password || !confirmPassword}
        >
          Зарегистрироваться
        </button>
      </div>
    </div>
  );
};

export default Register;
